------------------------------------------------------------
----- TRIGGER FOR __mj_UpdatedAt field for the projects table
------------------------------------------------------------
IF OBJECT_ID('[hubspot].[trgUpdateprojects]', 'TR') IS NOT NULL
    DROP TRIGGER [hubspot].[trgUpdateprojects];
GO
CREATE TRIGGER [hubspot].trgUpdateprojects
ON [hubspot].[projects]
AFTER UPDATE
AS
BEGIN
    SET NOCOUNT ON;
    UPDATE
        [hubspot].[projects]
    SET
        __mj_UpdatedAt = GETUTCDATE()
    FROM
        [hubspot].[projects] AS _organicTable
    INNER JOIN
        INSERTED AS I ON
        _organicTable.[hs_object_id] = I.[hs_object_id];
END;
GO
        